from fastapi import FastAPI, HTTPException, status
from pydantic import BaseModel, EmailStr, Field, field_validator
from typing import Optional
import uuid, re

app = FastAPI()

class UserCreate(BaseModel):
    name: str = Field(..., min_length=2, max_length=50)
    email: EmailStr
    age: Optional[int] = Field(None, ge=18, le=120)

    @field_validator('name')
    @classmethod
    def validate_name(cls, v: str) -> str:
        if not re.match(r'^[a-zA-Z\s\-\']+$', v):
            raise ValueError('Name must contain only letters, spaces, hyphens, apostrophes')
        return v.strip()

class UserResponse(BaseModel):
    user_id: str
    name: str
    email: str
    age: Optional[int]
    message: str

@app.post(
    '/api/users',
    response_model=UserResponse,
    status_code=status.HTTP_201_CREATED,
    responses={
        400: {'description': 'Bad Request'},
        422: {'description': 'Validation Error'},
    }
)
async def create_user(user: UserCreate) -> UserResponse:
    """Create a new user with validated input."""
    try:
        user_id = str(uuid.uuid4())
        return UserResponse(
            user_id=user_id,
            name=user.name,
            email=user.email,
            age=user.age,
            message='User created successfully'
        )
    except Exception as e:
        raise HTTPException(
            status_code=status.HTTP_400_BAD_REQUEST,
            detail=str(e)
        )

import { useState, useEffect } from 'react'

interface Todo {
  id: number
  text: string
  completed: boolean
}

const TodoList = () => {
  const [todos, setTodos] = useState<Todo[]>(() => {
    const saved = localStorage.getItem('todos')
    return saved ? JSON.parse(saved) : []
  })
  const [input, setInput] = useState('')

  useEffect(() => {
    localStorage.setItem('todos', JSON.stringify(todos))
  }, [todos])

  const addTodo = () => {
    const trimmed = input.trim()
    if (!trimmed) return
    setTodos(prev => [...prev, { id: Date.now(), text: trimmed, completed: false }])
    setInput('')
  }

  const toggleTodo = (id: number) =>
    setTodos(prev => prev.map(t => t.id === id ? { ...t, completed: !t.completed } : t))

  const deleteTodo = (id: number) =>
    setTodos(prev => prev.filter(t => t.id !== id))

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') addTodo()
  }

  return (
    <div style={{ maxWidth: 480, margin: '2rem auto', fontFamily: 'sans-serif' }}>
      <h1 style={{ fontSize: 22, marginBottom: '1rem' }}>Todo List</h1>
      <div style={{ display: 'flex', gap: 8, marginBottom: '1.5rem' }}>
        <input value={input} onChange={e => setInput(e.target.value)} onKeyDown={handleKeyDown}
          placeholder='Add a new todo...'
          style={{ flex: 1, padding: '8px 12px', border: '1px solid #ccc', borderRadius: 6 }} />
        <button onClick={addTodo} style={{ padding: '8px 16px', borderRadius: 6, cursor: 'pointer' }}>Add</button>
      </div>
      {todos.length === 0 && <p style={{ color: '#888', textAlign: 'center' }}>No todos yet!</p>}
      <ul style={{ listStyle: 'none', padding: 0 }}>
        {todos.map(todo => (
          <li key={todo.id} style={{ display: 'flex', alignItems: 'center', gap: 10,
            padding: '10px 12px', marginBottom: 6, border: '1px solid #eee', borderRadius: 6 }}>
            <input type='checkbox' checked={todo.completed} onChange={() => toggleTodo(todo.id)} />
            <span style={{ flex: 1, textDecoration: todo.completed ? 'line-through' : 'none',
              color: todo.completed ? '#aaa' : 'inherit' }}>{todo.text}</span>
            <button onClick={() => deleteTodo(todo.id)}
              style={{ color: '#e24b4a', border: 'none', background: 'transparent', cursor: 'pointer', fontSize: 16 }}>×</button>
          </li>
        ))}
      </ul>
    </div>
  )
}

export default TodoList

import jwt
from datetime import datetime, timezone
from dataclasses import dataclass
from typing import List
import os


@dataclass
class AuthenticatedUser:
    user_id: str
    email: str
    roles: List[str]


class TokenExpiredError(Exception):
    pass

class InvalidTokenError(Exception):
    pass

class MalformedTokenError(Exception):
    pass


SECRET_KEY = os.environ.get('JWT_SECRET_KEY', 'change-me-in-production')
ALGORITHM = 'HS256'


def verify_jwt_token(token: str) -> AuthenticatedUser:
    """
    Validates a JWT token and returns the authenticated user.

    Args:
        token: Raw JWT string.

    Returns:
        AuthenticatedUser with user_id, email, and roles.

    Raises:
        TokenExpiredError: Token has passed its expiration time.
        InvalidTokenError: Signature is invalid or issuer mismatch.
        MalformedTokenError: Token is not a valid JWT structure.
    """
    if not token or not isinstance(token, str):
        raise MalformedTokenError('Token must be a non-empty string')

    try:
        payload = jwt.decode(
            token,
            SECRET_KEY,
            algorithms=[ALGORITHM],
            options={'require': ['exp', 'sub', 'email']}
        )
    except jwt.ExpiredSignatureError:
        raise TokenExpiredError('Token has expired. Please log in again.')
    except jwt.InvalidSignatureError:
        raise InvalidTokenError('Token signature is invalid.')
    except jwt.DecodeError:
        raise MalformedTokenError('Token is malformed or not a valid JWT.')
    except jwt.InvalidTokenError as e:
        raise InvalidTokenError(f'Token validation failed: {str(e)}')

    user_id = payload.get('sub')
    email = payload.get('email')
    roles = payload.get('roles', [])

    if not user_id or not email:
        raise MalformedTokenError('Token payload is missing required fields: sub, email')

    if not isinstance(roles, list):
        raise MalformedTokenError('Roles claim must be a list')

    return AuthenticatedUser(user_id=str(user_id), email=str(email), roles=roles)
